mapper.select:
select c.*, b.name as brand_name
from car c
left join car_brand b on c.brand_id = b.id


        and (c.model like concat('%', #{keyword}, '%')
        or b.name like concat('%', #{keyword}, '%')
        or c.tag like concat('%', #{keyword}, '%'))


        and c.brand_id = #{brandId}


        and c.id in (select car_id from car_category_relation where category_id = #{categoryId})


        and c.seats = #{seats}


        and c.energy = #{energy}


        and c.status = #{status}


        and c.price >= #{minPrice}


        and c.price <= #{maxPrice}


order by c.create_time desc

mapper.update:
update car_brand
set name = #{name},
    sort_order = #{sortOrder},
    status = #{status}
where id = #{id}

update car_category
set name = #{name},
    code = #{code},
    sort_order = #{sortOrder},
    status = #{status}
where id = #{id}

mapper.select:
select c.id, c.brand_id, c.model, c.seats, c.gear, c.energy, c.year, c.price, c.rating, c.review_count, c.tag, c.image, c.features, b.name as brand_name from car c left join car_brand b on c.brand_id = b.id
c.status = 'available'
and ( b.name like concat('%', #{keyword}, '%') or c.model like concat('%', #{keyword}, '%') or c.tag like concat('%', #{keyword}, '%') or c.energy like concat('%', #{keyword}, '%') )
and c.brand_id = #{brandId}
and c.seats = #{seats}
and c.energy = #{energy}
and c.price >= #{minPrice}
and c.price <= #{maxPrice}
order by c.price asc
order by c.price desc
order by c.create_time desc
